def canPartitionKSubsets(nums: list[int], k: int) -> bool:
    total_sum = sum(nums)

    if total_sum % k != 0:
        return False

    target_sum = total_sum // k
    n = len(nums)

    if any(num > target_sum for num in nums):
        return False

    nums.sort(reverse=True)

    buckets = [0] * k

    def backtrack(idx):
        if idx == n:
            return True

        for i in range(k):
            if buckets[i] + nums[idx] <= target_sum:
                buckets[i] += nums[idx]
                if backtrack(idx + 1):
                    return True
                buckets[i] -= nums[idx]

            if buckets[i] == 0:
                break

        return False

    return backtrack(0)
